      accent: "#818cf8",
      sidebar: "#0f172a",
      editor: "#020617",
      terminal: "#010410",
      statusBar: "#0f172a",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
];

// ── Lookups ─────────────────────────────────────────────────────────

const themeMap = new Map<string, Theme>(
  BUILT_IN_THEMES.map((theme) => [theme.id, theme]),
);

export function getTheme(id: string): Theme | undefined {
  return themeMap.get(id);
}

export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

/**
 * Returns `true` when the theme's background color is perceptually dark.
 * Uses BT.601 luma derived from the background hex color.
 */
export function isDarkTheme(theme: Theme): boolean {
  const hex = theme.colors.background.replace("#", "");
  const r = parseInt(hex.substring(0, 2), 16);
  const g = parseInt(hex.substring(2, 4), 16);
  const b = parseInt(hex.substring(4, 6), 16);
  return (0.299 * r + 0.587 * g + 0.114 * b) / 255 < 0.5;
}

