import type { Theme } from "@t3tools/shared/themes";

import { useTheme } from "../hooks/useTheme";

// ── Swatch strip ────────────────────────────────────────────────────

const SWATCH_KEYS = ["background", "sidebar", "accent", "foreground"] as const;

function ThemeSwatches({ theme }: { theme: Theme }) {
  return (
    <div className="flex gap-1 rounded-md border border-border/50 p-1" aria-hidden="true">
      {SWATCH_KEYS.map((key) => (
        <div
          key={key}
          className="size-4 rounded-sm"
          style={{ backgroundColor: theme.colors[key] }}
        />
      ))}
    </div>
  );
}

// ── Selector ────────────────────────────────────────────────────────

export function ThemeSelector() {
  const { theme: currentTheme, setTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme">
      {availableThemes.map((t) => {
        const selected = t.id === currentTheme.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(t.id)}
          >
            <ThemeSwatches theme={t} />
            <span className="flex flex-col">
              <span className="text-sm font-medium">{t.name}</span>
            </span>
            {selected ? (
              <span className="ml-auto rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

