import {
  createContext,
  createElement,
  useCallback,
  useContext,
  useEffect,
  useState,
  type ReactNode,
} from "react";
import { type Theme, getTheme, isDarkTheme, listThemes } from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:custom-theme";
const DEFAULT_THEME_ID = "t3-dark";

// ── Context ─────────────────────────────────────────────────────────

interface ThemeContextValue {
  readonly theme: Theme;
  readonly setTheme: (id: string) => void;
  readonly availableThemes: readonly Theme[];
  /** Resolved appearance — "light" or "dark" — for components that only need the mode. */
  readonly resolvedTheme: "light" | "dark";
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

// ── Helpers ─────────────────────────────────────────────────────────

function getStoredThemeId(): string {
  if (typeof window === "undefined") return DEFAULT_THEME_ID;
  const stored = localStorage.getItem(STORAGE_KEY);
  if (typeof stored === "string" && getTheme(stored)) return stored;
  return DEFAULT_THEME_ID;
}

function resolveTheme(id: string): Theme {
  // eslint-disable-next-line @typescript-eslint/no-non-null-assertion -- DEFAULT_THEME_ID is always in the map
  return getTheme(id) ?? getTheme(DEFAULT_THEME_ID)!;
}

const THEME_CSS_PROPERTIES = [
  "background",
  "foreground",
  "accent",
  "sidebar",
  "editor",
  "terminal",
] as const;

function applyThemeToDocument(theme: Theme, suppressTransitions = false) {
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  // Apply CSS custom properties
  for (const prop of THEME_CSS_PROPERTIES) {
    root.style.setProperty(`--theme-${prop}`, theme.colors[prop]);
  }
  root.style.setProperty("--theme-status-bar", theme.colors.statusBar);
  root.style.setProperty("--theme-font-family", theme.fontFamily);
  root.style.setProperty("--theme-font-size", `${String(theme.fontSize)}px`);

  // Toggle dark class for Tailwind
  root.classList.toggle("dark", isDarkTheme(theme));

  if (suppressTransitions) {
    // Force reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash of unstyled content
applyThemeToDocument(resolveTheme(getStoredThemeId()));

// ── Provider ────────────────────────────────────────────────────────

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [theme, setThemeState] = useState<Theme>(() => resolveTheme(getStoredThemeId()));

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id);
    if (!next) return;
    localStorage.setItem(STORAGE_KEY, id);
    setThemeState(next);
    applyThemeToDocument(next, true);
  }, []);

  // Keep DOM in sync on mount
  useEffect(() => {
    applyThemeToDocument(theme);
  }, [theme]);

  // Sync when another tab changes the theme via localStorage
  useEffect(() => {
    const handleStorage = (event: StorageEvent) => {
      if (event.key !== STORAGE_KEY) return;
      const next = resolveTheme(getStoredThemeId());
      setThemeState(next);
      applyThemeToDocument(next, true);
    };
    window.addEventListener("storage", handleStorage);
    return () => window.removeEventListener("storage", handleStorage);
  }, []);

  const value: ThemeContextValue = {
    theme,
    setTheme,
    availableThemes: listThemes(),
    resolvedTheme: isDarkTheme(theme) ? "dark" : "light",
  };

  return createElement(ThemeContext.Provider, { value }, children);
}

// ── Hook ────────────────────────────────────────────────────────────

export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) {
    throw new Error("useTheme must be used within a ThemeProvider");
  }
  return ctx;
}

