// ── Theme types ─────────────────────────────────────────────────────

export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

export interface Theme {
  readonly id: string;
  readonly name: string;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: number;
}

// ── Built-in themes ─────────────────────────────────────────────────

const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colors: {
      background: "#0a0a0b",
      foreground: "#e5e5e5",
      accent: "#6366f1",
      sidebar: "#111113",
      editor: "#0a0a0b",
      terminal: "#080809",
      statusBar: "#111113",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colors: {
      background: "#ffffff",
      foreground: "#1a1a1a",
      accent: "#4f46e5",
      sidebar: "#f5f5f5",
      editor: "#ffffff",
      terminal: "#fafafa",
      statusBar: "#f0f0f0",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colors: {
      background: "#020617",
      foreground: "#e2e8f0",
      accent: "#818cf8",
      sidebar: "#0f172a",
      editor: "#020617",
      terminal: "#010410",
      statusBar: "#0f172a",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
];

// ── Lookups ─────────────────────────────────────────────────────────

const themeMap = new Map<string, Theme>(
  BUILT_IN_THEMES.map((theme) => [theme.id, theme]),
);

export function getTheme(id: string): Theme | undefined {
  return themeMap.get(id);
}

export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

/**
 * Returns `true` when the theme's background color is perceptually dark.
 * Uses BT.601 luma derived from the background hex color.
 */
export function isDarkTheme(theme: Theme): boolean {
  const hex = theme.colors.background.replace("#", "");
  const r = parseInt(hex.substring(0, 2), 16);
  const g = parseInt(hex.substring(2, 4), 16);
  const b = parseInt(hex.substring(4, 6), 16);
  return (0.299 * r + 0.587 * g + 0.114 * b) / 255 < 0.5;
}

